%[text] # Time-testing 3D data reads from the CEFI Data Portal(s)
%[text] ### Local read (after downloading file)
pth = 'vo.nep.full.hcast.monthly.raw.r20250912.199301-202506.nc';
t(:,1) = time_vo_reads_at_M2(pth); %[output:94662bf9]
%%
%[text] ### PSL-hosted CEFI Data Portal (OpenDAP)
pth = 'http://psl.noaa.gov/thredds/dodsC/Projects/CEFI/regional_mom6/cefi_portal/northeast_pacific/full_domain/hindcast/monthly/raw/r20250912/vo.nep.full.hcast.monthly.raw.r20250912.199301-202506.nc';
t(:,2) = time_vo_reads_at_M2(pth); %[output:7ba2f2ef]
%%
%[text] ### Earthmover (OpenDAP)
pth = 'https://compute.earthmover.io/v1/services/dap2/NOAA-PMEL/cefi-nep-hindcast-monthly/main/raw/main/opendap';
t(:,3) = time_vo_reads_at_M2(pth); %[output:19bc1285]
%%
%[text] ### Earthmover (OpenDAP, add-statics)
pth = 'https://compute.earthmover.io/v1/services/dap2/NOAA-PMEL/cefi-nep-hindcast-monthly/add-statics/raw/main/opendap';
t(:,4) = time_vo_reads_at_M2(pth); %[output:370a39ea]
%%
%[text] ### Comparison plots
vtestnames = {'z_i','z_l','vo along ih', 'vo along jq', ...
             'vo along time', 'vo along z_l'};
locs = {'local', 'PSL', 'Earthmover (main)', 'Earthmover (add-statics)'};


figure; ax(1) = axes; %[output:8fb253b1]
barh(seconds(t(1:6,:))); %[output:8fb253b1]
set(ax(1), 'ytick', 1:6, 'yticklabel', vtestnames); %[output:8fb253b1]
ax(1).YAxis.TickLabelInterpreter = 'none'; %[output:8fb253b1]
legend(locs, 'location', 'best'); %[output:8fb253b1]
figure; ax(2) = axes; %[output:14c80973]
barh((t(8:end-1,:))'./60, 'stacked', 'edgecolor', 'none') %[output:14c80973]
set(ax(2), 'ytick', 1:length(locs), 'yticklabel', locs); %[output:14c80973]
xlabel('minutes'); %[output:14c80973]
title('per-element reads of vo along z_l', 'interpreter', 'none'); %[output:14c80973]
%%
%[text] ### Can we use arraylake from Matlab?
%[text] We can open a dataset by taking advantage of Matlab's ability to call python modules.
% Initiate session by calling the python arraylake module

client = py.arraylake.Client();
repo = client.get_repo("NOAA-PMEL/cefi-nep-hindcast-monthly");
session = repo.readonly_session(branch="main");

% Read data by calling python xarray

ds = py.xarray.open_zarr(session.store, zarr_format=3, group="raw/main") %[output:32f6f167]
%%
%[text] Getting the data into a format usable within Matlab is a little trickier, since we can't directly recast ndarrays to double.  But we can get there if we first go from python ndarray to python list of numeric arrays to matlab cell array of doubles and then concatenate. 
%[text] Here's an example where we extract a small 2D static variable (geolat):
geolat = ds{'geolat'} %[output:4230b459]
geolatval = geolat.values %[output:6b9c3161]
geolatval = cellfun(@double, cell(geolatval.tolist()), 'uni', 0) %[output:32e7a07a]
geolatval = cat(1, geolatval{:}) %[output:1ca66e46]
%[text] We take advantage of the xarray dataset's lazy load to extract hyperslabs from larger variables.  Here's how we could read the M2 depth profile from a single time step (same as above example).
vo_at_m2 = nan(52,2); 

% Do not remove the semicolon from the ds{'vo'} command!  Matlab will try to read
% the entire array into memory to print its preview of values if you do
% that.  You don't want that!

tic
client = py.arraylake.Client();
repo = client.get_repo("NOAA-PMEL/cefi-nep-hindcast-monthly");
session = repo.readonly_session(branch="main");
ds = py.xarray.open_zarr(session.store, zarr_format=3, group="raw/main");
vo = ds{'vo'}; 
vo_at_m2_da = vo.isel(ih=int32(130),jq=int32(598),time=int32(0));
vo_at_m2(:,1) = double(vo_at_m2_da.values.tolist());
toc %[output:915eefba]
%[text] Compare that to an OpenDAP read
tic
emfile = 'https://compute.earthmover.io/v1/services/dap2/NOAA-PMEL/cefi-nep-hindcast-monthly/main/raw/main/opendap';
vo_at_m2(:,2) = ncread(emfile, 'vo', [131 599 1 1], [1 1 52 1]);
toc %[output:6bf83f1d]

isequaln(vo_at_m2(:,1), vo_at_m2(:,2)) %[output:86336f1b]
%[text] Conclusion: it works, but is slower and messier than a simple OpenDAP read, at least for a tiny operation like this.  Possibly worthwhile if doing calculation that takes more advantage of xarray's core abilities... but then probably better to just use straight python for it.
%%
%[text] ### The time-testing function
%[text] 
function t = time_vo_reads_at_M2(pth)

    t = nan(59,1);
    
    % Dimension variables (small, should be easily read)

    fprintf('Dimension variables:\n\n');
    fprintf('z_i: ');
    tic
    z_i = ncread(pth, 'z_i');
    t(1) = toc; printtime(t(1));
    
    fprintf('z_l: ');
    tic
    z_l = ncread(pth, 'z_l');
    t(2) = toc; printtime(t(2));
    
    % Read 52-element slices from a large 3D variable
    
    fprintf('\nAlong dimension tests (52x1 arrays):\n\n');
    
    fprintf('along ih  : ')
    tic
    tmp1 = ncread(pth, 'vo', [131 599 1 1], [52 1 1 1]);
    t(3) = toc; printtime(t(3));
    fprintf('along jq  : ')
    tic
    tmp2 = ncread(pth, 'vo', [131 599 1 1], [1 52 1 1]);
    t(4) = toc; printtime(t(4));
    fprintf('along time: ')
    tic
    tmp3 = ncread(pth, 'vo', [131 599 1 1], [1 1 1 52]);
    t(5) = toc; printtime(t(5));
    fprintf('along z_l : ')
    tic
    try
        tmp4 = ncread(pth, 'vo', [131 599 1 1], [1 1 52 1]);
        t(6) = toc; printtime(t(6));
    catch ME
        t(6) = toc; fprintf('Error: %s\n  ', ME.message); printtime(t(6));
    end
    
    % Read the depth profile one element at a time

    fprintf('\n3D variable, read one element at a time:\n\n');
    
    vo = nan(52,1);
    ttot = tic;
    for iz = 1:52
        fprintf('vo(%2d): ', iz);
        ti = tic;
        vo(iz) = ncread(pth, 'vo', [131 599 iz 1], [1 1 1 1]);
        t(iz+6) = toc(ti); printtime(t(iz+6));
    end
    fprintf('\ntotal: ');
    t(59) = toc(ttot); printtime(t(59));

end

function printtime(tsec)

    if tsec > 60
        fprintf('Elapsed time is %d min, %.6f seconds\n', floor(tsec/60), rem(tsec,60));
    else
        fprintf('Elapsed time is %.6f seconds\n', tsec);
    end

end


